+// hashPrefix returns a safe prefix of the hash for logging.
+// Returns up to 16 characters, or the full hash if shorter.
+func hashPrefix(hash string) string {
+	if len(hash) > 16 {
+		return hash[:16]
+	}
+	return hash
+}
